import { makeStyles } from '@material-ui/core/styles';

const useStyles = makeStyles((theme) => ({
  homeContainer: {
    position: 'relative',
  },
  heroImageContainer: {
    position: 'absolute',
    top: 0,
    left: 0,
    width: '100%',
    height: '100vh',
    zIndex: -1,
    overflow: 'hidden',
  },
  heroImage: {
    width: '100%',
    height: '100%',
    objectFit: 'cover',
  },
  contentContainer: {
    position: 'relative',
    textAlign: 'center',
    color: 'white',
  },
  welcomeText: {
    marginBottom: theme.spacing(3),
  },
  readMoreButton: {
    color: 'white',
    borderColor: 'white',
    '&:hover': {
      color: 'black',
      backgroundColor: 'white',
    },
  },
  imagesContainer: {
    position: 'relative',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
  },
  bottomImage: {
    width: '100%',
    height: 'auto',
    position: 'relative',
    zIndex: 1,
  },
  topImage: {
    width: '75%',
    height: 'auto',
    position: 'absolute',
    top: '25%',
    left: '12.5%',
    zIndex: 2,
  },
  hello: {
    color: 'white',
  },
}));

export default useStyles;
